  ('hypno_trance', 'Наведение открытости', 'Тренируй живую речь, образы и силу паузы — учись говорить так, чтобы тебя слушали', 'lightbulb', 'hypno_trance', '/chat', true, 14)
ON CONFLICT (key) DO NOTHING;

